import pickle
import os

class UserPreferences:
    def __init__(self):
        self.preferences = {}

def save_preferences(user_id, prefs):
    with open(f"user_{user_id}_prefs.pkl", "wb") as f:
        pickle.dump(prefs, f)

def load_preferences(user_id):
    try:
        with open(f"user_{user_id}_prefs.pkl", "rb") as f:
            return pickle.load(f)
    except FileNotFoundError:
        return {}
    except pickle.UnpicklingError:
        raise ValueError("Insecure deserialization detected")

